MOD = 10**9 + 7

def pw(a, n):
    """
    Compute the power of an integer `a` raised to the exponent `n` modulo `M` (10^9 + 7).
    """
    result = 1
    a = a % MOD
    while n > 0:
        if n % 2 == 1:
            result = (result * a) % MOD
        a = (a * a) % MOD
        n //= 2
    return result

def obr(x):
    """
    Compute the modular inverse of an integer `x` modulo `M` (10^9 + 7).
    """
    return pw(x, MOD - 2)

def cnk(n, k):
    """
    Compute the binomial coefficient `C(n, k)` modulo `M` (10^9 + 7).
    """
    if k < 0 or k > n:
        return 0
    if k == 0 or k == n:
        return 1
    if k > n // 2:
        k = n - k

    # Precompute factorials and their inverses
    fact = [1] * (n + 1)
    for i in range(1, n + 1):
        fact[i] = (fact[i-1] * i) % MOD

    return (fact[n] * obr(fact[k] * fact[n-k] % MOD)) % MOD

def solve(n, k, c):
    """
    Solve the problem by computing the number of nice paths of maximum length.

    A nice path can be divided into blocks of length exactly k, where each block
    has tiles of the same color.
    """
    # For each position, compute the maximum number of consecutive same-colored tiles
    # ending at that position
    same_len = [1] * n
    for i in range(1, n):
        if c[i] == c[i-1]:
            same_len[i] = same_len[i-1] + 1

    # DP: dp[i] = maximum number of blocks ending at position i
    # A block of color X of length k can extend a path if we have at least k tiles of color X
    dp = [0] * n
    for i in range(n):
        if same_len[i] >= k:
            # We can form a block ending at position i
            start_of_block = i - k + 1
            if start_of_block > 0:
                # Check if previous position has different color (valid block boundary)
                if c[start_of_block - 1] != c[i]:
                    dp[i] = 1 + dp[start_of_block - 1]
                else:
                    dp[i] = 1
            else:
                dp[i] = 1

    # Find maximum number of blocks
    max_blocks = max(dp) if n > 0 else 0

    # Count paths with maximum blocks
    count = 0
    for i in range(n):
        if dp[i] == max_blocks:
            count = (count + 1) % MOD

    return count
